// process_ledger.run() returns the totals dict; format a Telegram-ready summary.
const r = $input.first().json;
const chunks = r.chunks_inserted ?? 0;
const embedded = r.chunks_embedded ?? 0;
const papers = r.papers_inserted ?? 0;
const scored = r.relevance_scored ?? 0;
const failed = r.relevance_failed ?? 0;
const errs = r.errors ?? 0;
// Only post a Telegram summary when something happened OR an error occurred —
// chatty 30-min cron messages on quiet hours would burn the family's attention.
const noisy = (chunks + papers + scored + errs) > 0;
const summary = `📚 chunking-tick  +${papers} papers  +${chunks} chunks  +${embedded} embedded  +${scored} scored  ${errs ? '⚠️ '+errs+' errors' : ''}`;
return [{ json: { summary, noisy, ...r } }];
